import React, { useState } from 'react';
import Grid from '@material-ui/core/Grid';
import useStyles from './Layout/styles';
import { useTranslation } from 'react-i18next';
import LandingImageNorwegian from '../images/UllevaalStadion.png';
import LandingImageEnglish from '../images/landingImageEnglish.jpg';

const Home = () => {
  const classes = useStyles();
  const { t, i18n } = useTranslation();
  const [selectedLanguage, setSelectedLanguage] = useState(i18n.language);

  // Update the selected language when it changes
  i18n.on('languageChanged', (lng) => {
    setSelectedLanguage(lng);
  });

  const getImageSource = () => {
    // Conditionally return the appropriate image source based on the selected language
    return selectedLanguage === 'en' ? LandingImageEnglish : LandingImageNorwegian;
  };

  return (
    <Grid container>
      {/* homeContainer using Grid */}
      <Grid item xs={12} className={classes.homeContainer}>
        {/* Additional Sections using Grid */}
        <Grid container spacing={3}>
          <Grid item xs={12} sm={6}>
            <img
              className={classes.heroImage}
              src={getImageSource()}
              alt="Soccer Jersey Collection"
            />
          </Grid>

          <Grid item xs={12} sm={6}>
            {/* Your content for the second section */}
            <div className={classes.section}>
              {/* Content goes here */}
            </div>
          </Grid>

          {/* Add more Grid items for additional sections as needed */}
        </Grid>
      </Grid>
    </Grid>
  );
};

export default Home;
